snippet.async_client:
import asyncio

from seed import AsyncSeedApi

client = AsyncSeedApi(
    base_url="https://yourhost.com/path/to/api",
)


async def main() -> None:
    await client.create_plant(
        request={
            "name": "Venus Flytrap",
            "species": "Dionaea muscipula",
            "care": {
                "light": "full sun",
                "water": "distilled only",
                "humidity": "high",
            },
            "tags": ["carnivorous", "tropical"],
        },
    )


asyncio.run(main())

